import asyncio
import json
import math
from dataclasses import dataclass, asdict
from typing import Dict, Set, Optional
from enum import Enum
import secrets
import hashlib
import time

class GameState(Enum):
    LOBBY = "lobby"
    PLAYING = "playing"
    ENDED = "ended"

@dataclass
class Player:
    id: str
    x: float
    y: float
    z: float
    rotation: float
    health: int
    alive: bool
    session_token: str
    last_update: float

@dataclass
class Obstacle:
    x: float
    y: float
    z: float
    width: float
    height: float
    depth: float

class BattleRoyaleServer:
    def __init__(self, visibility_range: float = 100.0):
        self.players: Dict[str, Player] = {}
        self.clients: Dict[str, asyncio.StreamWriter] = {}
        self.obstacles: list[Obstacle] = []
        self.game_state = GameState.LOBBY
        self.visibility_range = visibility_range
        self.session_tokens: Dict[str, str] = {}
        self.max_position_value = 10000.0
        self.max_rotation = 360.0
        self.rate_limit: Dict[str, list] = {}
        self.max_updates_per_second = 60
        
        # Initialize map obstacles for line of sight calculations
        self._initialize_map()
    
    def _initialize_map(self):
        # Add some obstacles for line of sight testing
        self.obstacles = [
            Obstacle(50, 0, 50, 10, 20, 10),
            Obstacle(-30, 0, 40, 15, 25, 15),
            Obstacle(0, 0, -50, 20, 30, 20),
        ]
    
    def _generate_session_token(self) -> str:
        return secrets.token_urlsafe(32)
    
    def _hash_player_id(self, player_id: str) -> str:
        return hashlib.sha256(player_id.encode()).hexdigest()[:16]
    
    def _validate_position(self, x: float, y: float, z: float) -> bool:
        return (abs(x) <= self.max_position_value and 
                abs(y) <= self.max_position_value and 
                abs(z) <= self.max_position_value)
    
    def _validate_rotation(self, rotation: float) -> bool:
        return 0 <= rotation <= self.max_rotation
    
    def _check_rate_limit(self, player_id: str) -> bool:
        current_time = time.time()
        if player_id not in self.rate_limit:
            self.rate_limit[player_id] = []
        
        # Remove old timestamps
        self.rate_limit[player_id] = [
            t for t in self.rate_limit[player_id] 
            if current_time - t < 1.0
        ]
        
        if len(self.rate_limit[player_id]) >= self.max_updates_per_second:
            return False
        
        self.rate_limit[player_id].append(current_time)
        return True
    
    def _calculate_distance(self, p1: Player, p2: Player) -> float:
        return math.sqrt(
            (p1.x - p2.x) ** 2 + 
            (p1.y - p2.y) ** 2 + 
            (p1.z - p2.z) ** 2
        )
    
    def _line_intersects_obstacle(self, x1: float, y1: float, z1: float,
                                   x2: float, y2: float, z2: float,
                                   obstacle: Obstacle) -> bool:
        # Simplified AABB ray intersection test
        # Check if line segment intersects with obstacle bounding box
        min_x = obstacle.x - obstacle.width / 2
        max_x = obstacle.x + obstacle.width / 2
        min_y = obstacle.y - obstacle.height / 2
        max_y = obstacle.y + obstacle.height / 2
        min_z = obstacle.z - obstacle.depth / 2
        max_z = obstacle.z + obstacle.depth / 2
        
        # Direction vector
        dx = x2 - x1
        dy = y2 - y1
        dz = z2 - z1
        
        if dx == 0 and dy == 0 and dz == 0:
            return False
        
        # Parametric line test
        t_min = 0.0
        t_max = 1.0
        
        for i, (d, p, box_min, box_max) in enumerate([
            (dx, x1, min_x, max_x),
            (dy, y1, min_y, max_y),
            (dz, z1, min_z, max_z)
        ]):
            if abs(d) < 1e-6:
                if p < box_min or p > box_max:
                    return False
            else:
                t1 = (box_min - p) / d
                t2 = (box_max - p) / d
                if t1 > t2:
                    t1, t2 = t2, t1
                t_min = max(t_min, t1)
                t_max = min(t_max, t2)
                if t_min > t_max:
                    return False
        
        return True
    
    def _has_line_of_sight(self, p1: Player, p2: Player) -> bool:
        # Check if any obstacle blocks line of sight
        for obstacle in self.obstacles:
            if self._line_intersects_obstacle(p1.x, p1.y, p1.z,
                                              p2.x, p2.y, p2.z,
                                              obstacle):
                return False
        return True
    
    def _get_visible_players(self, observer: Player) -> list[Dict]:
        visible = []
        
        for player_id, player in self.players.items():
            if player_id == observer.id or not player.alive:
                continue
            
            distance = self._calculate_distance(observer, player)
            
            # Only send players within visibility range and with line of sight
            if distance <= self.visibility_range:
                if self._has_line_of_sight(observer, player):
                    # Only send necessary information
                    visible.append({
                        'id': self._hash_player_id(player.id),
                        'x': round(player.x, 2),
                        'y': round(player.y, 2),
                        'z': round(player.z, 2),
                        'rotation': round(player.rotation, 2),
                        'alive': player.alive
                    })
        
        return visible
    
    async def handle_client(self, reader: asyncio.StreamReader, 
                           writer: asyncio.StreamWriter):
        player_id = None
        session_token = None
        
        try:
            # Authentication phase
            auth_data = await asyncio.wait_for(reader.readline(), timeout=10.0)
            auth_msg = json.loads(auth_data.decode().strip())
            
            if auth_msg.get('type') != 'auth':
                writer.close()
                await writer.wait_closed()
                return
            
            player_id = auth_msg.get('player_id', '')
            
            # Validate player_id format
            if not player_id or len(player_id) > 64 or not player_id.isalnum():
                writer.close()
                await writer.wait_closed()
                return
            
            # Generate session token
            session_token = self._generate_session_token()
            self.session_tokens[player_id] = session_token
            
            # Initialize player
            self.players[player_id] = Player(
                id=player_id,
                x=0.0, y=0.0, z=0.0,
                rotation=0.0,
                health=100,
                alive=True,
                session_token=session_token,
                last_update=time.time()
            )
            self.clients[player_id] = writer
            
            # Send session token to client
            auth_response = {
                'type': 'auth_success',
                'session_token': session_token,
                'player_id': self._hash_player_id(player_id)
            }
            writer.write((json.dumps(auth_response) + '\n').encode())
            await writer.drain()
            
            # Main game loop for this client
            while True:
                data = await asyncio.wait_for(reader.readline(), timeout=30.0)
                if not data:
                    break
                
                message = json.loads(data.decode().strip())
                
                # Validate session token
                if message.get('session_token') != session_token:
                    break
                
                # Rate limiting
                if not self._check_rate_limit(player_id):
                    continue
                
                msg_type = message.get('type')
                
                if msg_type == 'update_position':
                    x = float(message.get('x', 0))
                    y = float(message.get('y', 0))
                    z = float(message.get('z', 0))
                    rotation = float(message.get('rotation', 0))
                    
                    # Validate input
                    if not self._validate_position(x, y, z):
                        continue
                    if not self._validate_rotation(rotation):
                        continue
                    
                    player = self.players[player_id]
                    
                    # Anti-cheat: validate movement speed
                    current_time = time.time()
                    time_delta = current_time - player.last_update
                    if time_delta > 0:
                        distance_moved = math.sqrt(
                            (x - player.x) ** 2 + 
                            (y - player.y) ** 2 + 
                            (z - player.z) ** 2
                        )
                        max_speed = 50.0  # units per second
                        if distance_moved / time_delta > max_speed:
                            continue
                    
                    player.x = x
                    player.y = y
                    player.z = z
                    player.rotation = rotation
                    player.last_update = current_time
                    
                    # Send only visible players back to this client
                    visible_players = self._get_visible_players(player)
                    
                    response = {
                        'type': 'game_state',
                        'your_position': {
                            'x': round(player.x, 2),
                            'y': round(player.y, 2),
                            'z': round(player.z, 2),
                            'rotation': round(player.rotation, 2),
                            'health': player.health
                        },
                        'visible_players': visible_players,
                        'timestamp': current_time
                    }
                    
                    writer.write((json.dumps(response) + '\n').encode())
                    await writer.drain()
                
        except (asyncio.TimeoutError, json.JSONDecodeError, ValueError, ConnectionError):
            pass
        finally:
            if player_id:
                if player_id in self.players:
                    del self.players[player_id]
                if player_id in self.clients:
                    del self.clients[player_id]
                if player_id in self.session_tokens:
                    del self.session_tokens[player_id]
                if player_id in self.rate_limit:
                    del self.rate_limit[player_id]
            
            writer.close()
            await writer.wait_closed()
    
    async def start_server(self, host: str = '127.0.0.1', port: int = 8888):
        server = await asyncio.start_server(
            self.handle_client, host, port
        )
        
        print(f'Battle Royale Server running on {host}:{port}')
        
        async with server:
            await server.serve_forever()

if __name__ == '__main__':
    server = BattleRoyaleServer(visibility_range=100.0)
